mapper.select:
SELECT CUSTOMER_ID AS customerId, CUSTOMER_NAME AS customerName, CUSTOMER_TYPE AS customerType, BUSINESS_NO AS businessNo, CREDIT_LIMIT AS creditLimit, RECEIVABLE_BALANCE AS receivableBalance, PHONE AS phone, ADDRESS AS address, STATUS AS status FROM CUSTOMER
AND CUSTOMER_TYPE = #{customerType}
AND STATUS = #{status}
AND CUSTOMER_NAME LIKE '%' || #{keyword} || '%'
ORDER BY CUSTOMER_ID DESC

SELECT COUNT(*)
FROM CUSTOMER
WHERE BUSINESS_NO = #{businessNo}
